// Middleware to apply plugins
function applyPlugins(pluginNames) {
  return (req, res, next) => {
    const pluginPromises = pluginNames.map(name => {
      const plugin = pluginLoader.plugins.get(name);
      if (!plugin) return Promise.resolve();
      
      return new Promise((resolve) => {
        try {
          plugin.execute(req, res, () => resolve());
        } catch (error) {
          console.error('Plugin execution error:', error.message);
          resolve();
        }
      });
    });

    Promise.all(pluginPromises)
      .then(() => next())
      .catch(next);
  };
}

